using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    // Initialize a 2D array to store the minimum cost to reach each cell
    vector<vector<long long>> dp(m, vector<long long>(n, LONG_MAX));

    // Starting cell (0, 0)
    dp[0][0] = (0 + 1) * (0 + 1); // Entry cost

    // Directions: right (0, 1), down (1, 0)
    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};

    // Use a priority queue to perform Dijkstra's algorithm
    // Each element is a tuple: (total_cost, time, row, col)
    priority_queue<pair<long long, pair<int, pair<int, int>>>> pq;
    pq.push({dp[0][0], 1, 0, 0});

    while (!pq.empty()) {
        long long total_cost = pq.top().first;
        int time = pq.top().second.first;
        int row = pq.top().second.second.first;
        int col = pq.top().second.second.second;
        pq.pop();

        // If we have already found a better path to this cell, skip
        if (total_cost > dp[row][col]) {
            continue;
        }

        // If we have reached the destination, return the total cost
        if (row == m - 1 && col == n - 1) {
            return total_cost;
        }

        // Check if we can move right or down
        for (auto& dir : directions) {
            int newRow = row + dir.first;
            int newCol = col + dir.second;

            // Check if the new position is within bounds
            if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                // Calculate the entry cost of the new cell
                long long entryCost = (newRow + 1) * (newCol + 1);
                long long newTotalCost = total_cost + entryCost;

                // If the new time is odd (since time starts at 1), we can move
                if (time + 1 % 2 == 1) {
                    // Update the dp value if this is a better path
                    if (newTotalCost < dp[newRow][newCol]) {
                        dp[newRow][newCol] = newTotalCost;
                        pq.push({newTotalCost, time + 1, newRow, newCol});
                    }
                }
            }
        }

        // If the current time is even, we need to wait
        if (time % 2 == 0) {
            long long waitCostValue = waitCost[row][col];
            long long newTotalCost = total_cost + waitCostValue;

            // If this is a better path, update and push to the queue
            if (newTotalCost < dp[row][col]) {
                dp[row][col] = newTotalCost;
                pq.push({newTotalCost, time + 1, row, col});
            }
        }
    }

    // If we reach here, no path was found (should not happen in valid inputs)
    return -1;
